body.raw:
// Emit this event
socket.emit('join-video-call', {
  consultationId: '{{consultation_id}}'
});

// Listen for response
socket.on('call-room-joined', ({ callId, roomId }) => {
  console.log('Joined call:', callId);
  // Start WebRTC connection
});

socket.on('peer-joined', ({ peerId }) => {
  console.log('Peer joined:', peerId);
});

// Send offer
socket.emit('webrtc-offer', {
  to: 'expert_user_id',
  callId: '{{call_id}}',
  offer: sdpOffer  // RTCSessionDescription
});

// Receive offer
socket.on('webrtc-offer', ({ from, offer }) => {
  console.log('Received offer from:', from);
  await pc.setRemoteDescription(offer);
});

// Send answer
socket.emit('webrtc-answer', {
  to: 'patient_user_id',
  callId: '{{call_id}}',
  answer: sdpAnswer  // RTCSessionDescription
});

// Receive answer
socket.on('webrtc-answer', ({ from, answer }) => {
  console.log('Received answer from:', from);
  await pc.setRemoteDescription(answer);
});

// Send ICE candidate
socket.emit('ice-candidate', {
  to: 'peer_user_id',
  callId: '{{call_id}}',
  candidate: iceCandidate
});

// Receive ICE candidate
socket.on('ice-candidate', async ({ from, candidate }) => {
  console.log('Received ICE candidate from:', from);
  await pc.addIceCandidate(candidate);
});

// End the call
socket.emit('end-video-call', {
  callId: '{{call_id}}'
});

// Listen for call ended
socket.on('call-ended', ({ callId }) => {
  console.log('Call ended:', callId);
  // Close peer connection
  pc.close();
});
